namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories = new List<RecipeCategory>
        {
            new() { Name = "Breakfast", Description = "Start your day right with hearty morning meals", Icon = "🍳" },
            new() { Name = "Lunch", Description = "Quick and satisfying midday recipes", Icon = "🥗" },
            new() { Name = "Dinner", Description = "Impressive evening meals for the whole family", Icon = "🍝" },
            new() { Name = "Desserts", Description = "Sweet treats to end any meal on a high note", Icon = "🍰" },
            new() { Name = "Snacks", Description = "Light bites for any time of day", Icon = "🥨" },
            new() { Name = "Beverages", Description = "Refreshing drinks and smoothies", Icon = "🥤" }
        };

        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt\nButter for cooking", Steps = "1. Mix dry ingredients in a bowl.\n2. Whisk eggs and milk together.\n3. Combine wet and dry ingredients until just mixed.\n4. Heat a buttered pan over medium heat.\n5. Pour 1/4 cup batter per pancake.\n6. Flip when bubbles form on surface.\n7. Cook until golden brown.", AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Caesar Salad", Category = "Lunch", Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan cheese\nCaesar dressing\nGrilled chicken (optional)", Steps = "1. Wash and chop romaine lettuce.\n2. Toss with Caesar dressing.\n3. Add croutons and shaved parmesan.\n4. Top with grilled chicken if desired.\n5. Serve immediately.", AverageRating = 4.2, RatingCount = 8 },
            new() { Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner", Ingredients = "400g spaghetti\n500g ground beef\n1 onion, diced\n3 cloves garlic\n400g crushed tomatoes\n2 tbsp tomato paste\nOlive oil\nSalt, pepper, Italian herbs", Steps = "1. Cook spaghetti according to package.\n2. Sauté onion and garlic in olive oil.\n3. Brown the ground beef.\n4. Add crushed tomatoes and tomato paste.\n5. Season with salt, pepper, and herbs.\n6. Simmer for 20 minutes.\n7. Serve sauce over spaghetti.", AverageRating = 4.8, RatingCount = 24 },
            new() { Id = 4, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "200g dark chocolate\n100g butter\n3 eggs\n100g sugar\n50g flour\nButter and cocoa for ramekins", Steps = "1. Preheat oven to 220°C (425°F).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until fluffy.\n4. Fold in chocolate mixture.\n5. Add flour gently.\n6. Pour into greased ramekins.\n7. Bake for 12 minutes.\n8. Invert onto plates and serve immediately.", AverageRating = 4.9, RatingCount = 31 },
            new() { Id = 5, Title = "Guacamole", Category = "Snacks", Ingredients = "3 ripe avocados\n1 lime, juiced\n1 tsp salt\n1/2 cup onion, diced\n3 tbsp fresh cilantro\n2 roma tomatoes, diced\n1 tsp minced garlic\n1 pinch cayenne pepper", Steps = "1. Cut avocados in half and remove pit.\n2. Scoop out flesh and mash with a fork.\n3. Stir in lime juice and salt.\n4. Mix in onion, cilantro, tomatoes, and garlic.\n5. Add cayenne pepper.\n6. Refrigerate for 1 hour before serving.", AverageRating = 4.6, RatingCount = 15 },
            new() { Id = 6, Title = "Berry Smoothie", Category = "Beverages", Ingredients = "1 cup mixed berries\n1 banana\n1 cup yogurt\n1/2 cup milk\n1 tbsp honey\nIce cubes", Steps = "1. Add all ingredients to a blender.\n2. Blend until smooth.\n3. Add more milk if too thick.\n4. Pour into a glass and serve immediately.", AverageRating = 4.3, RatingCount = 9 }
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAllRecipes() => _recipes;

    public void AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _recipes.Max(r => r.Id) + 1,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        };
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && rating >= 1 && rating <= 5)
        {
            var totalRating = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
        }
    }
}

