arguments.file_text:
@rendermode InteractiveServer

<div class="star-rating">
    <span class="rating-label">@(CurrentRating > 0 ? $"{CurrentRating:F1}" : "Rate this") (@RatingCount ratings)</span>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= SelectedRating ? "filled" : star <= Math.Round(CurrentRating) ? "average" : "")"
                  @onclick="() => Rate(star)"
                  title="@star star(s)">★</span>
        }
    </div>
    @if (_submitted)
    {
        <span class="rating-thanks">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    [Inject] private Services.RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating;
    private bool _submitted;

    private void Rate(int rating)
    {
        SelectedRating = rating;
        RecipeService.RateRecipe(RecipeId, rating);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        _submitted = true;
    }
}

@page "/"

<PageTitle>Recipe Community - Home</PageTitle>

<div class="hero">
    <h1>🍽️ Recipe Community</h1>
    <p class="lead">Discover, share, and rate delicious recipes from our community of home cooks.</p>
</div>

<h2>Browse by Category</h2>
<div class="category-grid">
    @foreach (var category in Categories)
    {
        <a href="/recipes/@category.Name.ToLower()" class="category-card">
            <span class="category-icon">@category.Icon</span>
            <h3>@category.Name</h3>
            <p>@category.Description</p>
        </a>
    }
</div>

<div class="cta-section">
    <h2>Got a recipe to share?</h2>
    <p>Join our community and submit your favorite recipes!</p>
    <a href="/submit" class="btn-submit">Submit a Recipe</a>
</div>

@code {
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeCommunity.Models.RecipeCategory> Categories = new();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

@page "/recipes/{CategoryName}"

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<h1>@CategoryName Recipes</h1>
<p><a href="/">← Back to Categories</a></p>

@if (Recipes.Any())
{
    <div class="recipe-list">
        @foreach (var recipe in Recipes)
        {
            <a href="/recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <div class="recipe-meta">
                    <span class="stars-display">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                    <span>@recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                </div>
            </a>
        }
    </div>
}
else
{
    <p>No recipes found in this category yet. <a href="/submit">Be the first to submit one!</a></p>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeCommunity.Models.Recipe> Recipes = new();

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

@if (Recipe is not null)
{
    <article class="recipe-detail">
        <p><a href="/recipes/@Recipe.Category.ToLower()">← Back to @Recipe.Category</a></p>
        <h1>@Recipe.Title</h1>

        <RecipeCommunity.Components.Shared.StarRating
            RecipeId="@Recipe.Id"
            CurrentRating="@Recipe.AverageRating"
            RatingCount="@Recipe.RatingCount" />

        <section class="recipe-section">
            <h2>🧾 Ingredients</h2>
            <ul class="ingredients-list">
                @foreach (var ingredient in Recipe.Ingredients.Split('\n'))
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section class="recipe-section">
            <h2>👨‍🍳 Instructions</h2>
            <div class="steps">
                @foreach (var step in Recipe.Steps.Split('\n'))
                {
                    <p>@step</p>
                }
            </div>
        </section>
    </article>
}
else
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe. <a href="/">Browse all categories</a></p>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.Recipe? Recipe;

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="success-message">
        <h2>✅ Recipe Submitted!</h2>
        <p>Thank you for sharing "<strong>@_submission.Title</strong>" with the community.</p>
        <a href="/">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" class="recipe-form">
        <DataAnnotationsValidator />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="_submission.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="_submission.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in _categories)
                {
                    <option value="@cat.Name">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_submission.Ingredients" rows="6"
                placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_submission.Steps" rows="8"
                placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
        </div>

        <button type="submit" class="btn-submit"
            disabled="@(string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.RecipeSubmission _submission = new();
    private List<RecipeCommunity.Models.RecipeCategory> _categories = new();
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(_submission.Title) && !string.IsNullOrWhiteSpace(_submission.Category))
        {
            RecipeService.AddRecipe(_submission);
            _submitted = true;
        }
    }
}

